    pageName: "How crowdsourced delivery can help businesses win and keep customers in the last mile",


    redirectUrl: "https:\/\/www.roadie.com\/resources\/white-papers\/how-crowdsourced-delivery-can-help-businesses-win-and-keep-customers-in-the-last-mile-thank-you",





    css: '',
    target: '#hs_form_target_form_787319560',







    contentType: "landing-page",



    formsBaseUrl: '/_hcms/forms/',



    formData: {
        cssClass: 'hs-form stacked hs-custom-form'
    }
};

options.getExtraMetaDataBeforeSubmit = function() {
    var metadata = {};


    if (hbspt.targetedContentMetadata) {
        var count = hbspt.targetedContentMetadata.length;
        var targetedContentData = [];
        for (var i = 0; i < count; i++) {
            var tc = hbspt.targetedContentMetadata[i];
             if ( tc.length !== 3) {
                continue;
             }
             targetedContentData.push({
                definitionId: tc[0],
                criterionId: tc[1],
                smartTypeId: tc[2]
             });
        }
        metadata["targetedContentMetadata"] = JSON.stringify(targetedContentData);
    }

    return metadata;
};

hbspt.forms.create(options);

$(document).ready(function(){
	function checkHeight(){
		var formHeight = $('.form_column_inner').outerHeight();
		var calcHeight = formHeight + 200;
		$('.split_form_wrapper.formAdded').css('min-height',calcHeight);
		console.log('checkHeight call')
	}

	$(window).on("load resize", function() {
		setTimeout(function(){
			checkHeight();
		}, 200)
	});

	// HubSpot form submission detection
	if (window.hbspt) {
		console.log('hbspt call')

		// Function to setup form listeners
		function setupFormListeners() {
			var forms = document.querySelectorAll('form.hs-form');
			forms.forEach(function(form) {
				// Listen for submit button clicks
				var submitButton = form.querySelector('input[type="submit"]');
				if (submitButton) {
					submitButton.addEventListener('click', function() {
						console.log('Submit button clicked');
						setTimeout(function(){
							checkHeight();
						}, 200);
					});
				}

				// Listen for validation state changes
				form.addEventListener('invalid', function(e) {
					console.log('Form validation error');
					setTimeout(function(){
						checkHeight();
					}, 200);
				}, true);

				// Listen for form submission
				form.addEventListener('submit', function(e) {
					console.log('Form submit event');
					setTimeout(function(){
						checkHeight();
					}, 200);
				});
			});
		}

		// Wait for forms to be ready
		setTimeout(setupFormListeners, 1000);
	}

	$('.split_form_wrapper.formAdded').parents('body').addClass('formsec');
});
